hniques.","jurisdiction_note":null,"sort":5},{"id":"vt","code":"VT","name":"Visual Testing","cp105":"ANSI/ASNT CP-105-2024 VT Topical Outlines","hours":{"snt_tc_1a":{"l1":8,"l2":16},"nas410":{"l1":null,"l2":null},"directToL2":24},"exam_method":null,"summary":"Direct and remote visual inspection, lighting and measurement requirements, borescope operation and technique, and acceptance criteria.","jurisdiction_note":null,"sort":6},{"id":"basic","code":"BASIC","name":"NDT Basic (Level III Prep)","cp105":"ANSI/ASNT CP-105-2024 Basic Examination Topical Outlines","hours":{"snt_tc_1a":{"l1":null,"l2":null},"nas410":{"l1":null,"l2":null},"directToL2":null},"exam_method":null,"summary":"Materials and processes, discontinuity origins, and a survey of all major NDT methods — the starting point for new technicians and the Level III Basic exam.","jurisdiction_note":null,"sort":7},{"id":"rad","code":"RS","name":"Radiation Safety","cp105":"ANSI/ASNT CP-105-2024 Appendix A: Radiographic Safety Operations and Emergency Instructions Course","hours":{"snt_tc_1a":{"l1":null,"l2":null},"nas410":{"l1":null,"l2":null},"directToL2":null},"exam_method":null,"summary":"Radiation fundamentals, dose limits, survey instruments, regulations, and emergency procedures for industrial radiographers and card holders.","jurisdiction_note":"Radiation safety training-hour and content requirements are established by the regulatory jurisdiction (NRC/Agreement State or other applicable authority) and must be verified against the applicable regulations; this course documents formal training only.","sort":8}]$NDTA_SEED$::jsonb)
