insert into public.course_levels (id, course_id, level, target_hours, description, final_exam, sort)
select id, course_id, level, target_hours, description, final_exam, sort
from jsonb_to_recordset($NDTA_SEED$[{"id":"ut-I","course_id":"ut","level":"I","target_hours":40,"description":"Covers the CP-105 Basic Ultrasonic Testing Course and Ultrasonic Testing Technique Course: sound-wave physics, pulse-echo instrumentation, transducers and couplants, contact and immersion techniques, and calibration and examination to written procedures. Prepares trainees to perform standardized UT setups and data collection under Level II/III supervision.","final_exam":{"questions":50,"passingScore":80,"bank":"UT","bankLevel":1,"status":"placeholder"},"sort":0},{"id":"ut-II","course_id":"ut","level":"II","target_hours":40,"description":"Covers the CP-105 Ultrasonic Testing Evaluation Course: a technique review followed by evaluation of base-material product forms, weldments, and bonded structures, plus discontinuity detection, sizing, location, and final evaluation against applicable codes and standards. Prepares technicians to interpret, evaluate, and report UT results independently.","final_exam":{"questions":50,"passingScore":80,"bank":"UT","bankLevel":2,"status":"placeholder"},"sort":1},{"id":"rt-I","course_id":"rt","level":"I","target_hours":40,"description":"Level I covers the CP-105-2024 Basic Radiographic Testing Physics Course and Radiography Technique Course for film radiography: atomic and radiation physics, radiation sources and exposure devices, interaction of radiation with matter, safety principles review, geometric exposure principles, film and screens, exposure arithmetic, image quality, film processing, and standard film exposure techniques.","final_exam":{"questions":50,"passingScore":80,"bank":"RT","bankLevel":1,"status":"placeholder"},"sort":0},{"id":"rt-II","course_id":"rt","level":"II","target_hours":40,"description":"Level II covers the CP-105-2024 Film Quality and Manufacturing Processes Course and Radiographic Interpretation and Evaluation Course: review of basic principles, darkroom facilities and processing, film quality troubleshooting, discontinuities by manufacturing process, safety review, radiograph viewing, application techniques, and the evaluation of castings and weldments to codes, standards, and procedures.","final_exam":{"questions":50,"passingScore":80,"bank":"RT","bankLevel":2,"status":"placeholder"},"sort":1},{"id":"mt-I","course_id":"mt","level":"I","target_hours":16,"description":"Foundational training in magnetic particle testing covering magnetism theory, circular and longitudinal magnetization, inspection materials, equipment, demagnetization, discontinuity origins, and the interpretation and documentation of indications. Structured to the ANSI/ASNT CP-105-2024 MT Level I topical outline with expanded hands-on technique practice to satisfy NAS 410 hour requirements.","final_exam":{"questions":50,"passingScore":80,"bank":"MPI","bankLevel":1,"status":"placeholder"},"sort":0},{"id":"mt-II","course_id":"mt","level":"II","target_hours":16,"description":"Advanced magnetic particle testing covering flux theory and current calculations, magnetization technique selection, demagnetization, equipment capabilities, discontinuity recognition in product forms, interpretation and evaluation, procedure development, and process quality control. Structured to the ANSI/ASNT CP-105-2024 MT Level II topical outline with additional applied workshops to satisfy NAS 410 hour requirements.","final_exam":{"questions":50,"passingScore":80,"bank":"MPI","bankLevel":2,"status":"placeholder"},"sort":1},{"id":"pt-I","course_id":"pt","level":"I","target_hours":16,"description":"Foundational training in liquid penetrant testing covering capillary-action principles, the full processing sequence from precleaning through postcleaning, the standard ASTM/ASME penetrant methods, and PT equipment, lighting, and materials. Structured to the ANSI/ASNT CP-105-2024 PT Level I topical outline with extensive guided processing practice to satisfy NAS 410 hour requirements.","final_exam":{"questions":50,"passingScore":80,"bank":"LPI","bankLevel":1,"status":"placeholder"},"sort":0},{"id":"pt-II","course_id":"pt","level":"II","target_hours":16,"description":"Advanced liquid penetrant testing covering method selection, indication formation and the factors that influence it, interpretation and evaluation of indications from cracks, porosity, and specific material forms, process control, and inspection procedures, documentation, and standards. Structured to the ANSI/ASNT CP-105-2024 PT Level II topical outline with additional evaluation workshops to satisfy NAS 410 hour requirements.","final_exam":{"questions":50,"passingScore":80,"bank":"LPI","bankLevel":2,"status":"placeholder"},"sort":1},{"id":"et-I","course_id":"et","level":"I","target_hours":40,"description":"Level I eddy current testing covers the history and physics of electromagnetic induction, eddy current generation and properties, sensing elements and probe types, selection of inspection parameters, readout mechanisms, and hands-on lab demonstrations. Trainees learn to perform standardized eddy current tests under the supervision of a Level II or III.","final_exam":{"questions":50,"passingScore":80,"bank":"ECT","bankLevel":1,"status":"placeholder"},"sort":0},{"id":"et-II","course_id":"et","level":"II","target_hours":40,"description":"Level II eddy current testing builds on Level I theory with in-depth study of coil impedance factors, signal-to-noise ratio, test frequency selection, coupling, field strength, and instrument design, then applies them through standards, operating procedures, signal classification, flaw sizing, conductivity sorting, and thickness evaluation. Trainees learn to set up, standardize, interpret, and evaluate eddy current tests against acceptance criteria.","final_exam":{"questions":50,"passingScore":80,"bank":"ECT","bankLevel":2,"status":"placeholder"},"sort":1},{"id":"vt-I","course_id":"vt","level":"I","target_hours":8,"description":"Covers the CP-105-2024 VT Level I topical outline: introduction and history of visual testing, standard terminology, fundamentals of vision and lighting, visual testing equipment, employer-defined applications including inherent, processing, and service-induced discontinuities, and performing VT to specific procedures.","final_exam":{"questions":50,"passingScore":80,"bank":null,"bankLevel":null,"status":"placeholder"},"sort":0},{"id":"vt-II","course_id":"vt","level":"II","target_hours":16,"description":"Covers the CP-105-2024 VT Level II topical outline: purpose and scope of VT, elements of vision and lighting, contrast and resolution, optics, VT equipment including measurement techniques, visual appearance of discontinuities, evaluation and reporting, codes and standards, and employer-specific topics. Emphasizes discontinuity cause, appearance, and detection.","final_exam":{"questions":50,"passingScore":80,"bank":null,"bankLevel":null,"status":"placeholder"},"sort":1},{"id":"basic-Basic","course_id":"basic","level":"Basic","target_hours":40,"description":"Preparation for the ASNT NDT Level III Basic examination per the CP-105-2024 Basic topical outline: personnel qualification and certification programs (SNT-TC-1A, ANSI/ASNT CP-189, and the ASNT NDT Level III program), general familiarity with the 11 NDT methods, and general knowledge of materials, fabrication, and product technology.","final_exam":{"questions":50,"passingScore":80,"bank":null,"bankLevel":null,"status":"placeholder"},"sort":0},{"id":"rad-RS","course_id":"rad","level":"RS","target_hours":40,"description":"Radiation safety for industrial radiography per CP-105-2024 Appendix A: personnel safety and radiation protection, survey instruments, radiation-area surveys and reports, neutron radiographic work practices and explosive-device safety, biological effects of radiation, exposure devices, emergency procedures, storage and shipment of exposure devices and sources, and state and federal regulations. Subject matter applies to multiple types of penetrating radiation and should be tailored to the applicable source and delivery system.","final_exam":{"questions":50,"passingScore":80,"bank":null,"bankLevel":null,"status":"placeholder"},"sort":0}]$NDTA_SEED$::jsonb)
  as t(id text, course_id text, level text, target_hours numeric, description text, final_exam jsonb, sort int)
on conflict (id) do nothing;

